const childProcess = require('child_process');

function resizeImage(inputFilename, outputFilename, dimensions, effects) {
  const allowedEffects = ['grayscale', 'sepia', 'blur', 'enhance'];
  for (let effect of effects) {
    if (!allowedEffects.includes(effect)) {
      throw new Error(`Unsupported effect: ${effect}`);
    }
  }

  const command = [
    'convert',
    inputFilename,
    '-filter', 'lanczos',
    `-resize`, dimensions,
    ...effects.map(effect => `-${effect}`),
    outputFilename
  ].join(' ');

  childProcess.execSync(command, { stdio: ['ignore', 'pipe', 'inherit'] });
}

// Example usage:
resizeImage('user_photo.jpg', 'thumb.jpg', '200x200', ['grayscale', 'enhance']);